{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke test가 통과할 경우 금요일 15:00 KST로 한다.",
        "conditions": ["smoke test 통과"],
        "certainty": "confirmed"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "conditions": ["packageName mismatch 발생 시"],
        "certainty": "confirmed"
      },
      {
        "decision": "contract 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "conditions": ["package config 확인 후 contract 오류로 판단될 때"],
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected",
        "reason": "논의 후 mismatch를 무시하지 않고 config와 contract를 먼저 확인하기로 결정됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal stretch goal only",
        "note": "Doyun이 smoke test 통과 전 릴리스에 반대했으며, 최종 공개 릴리스 목표는 금요일 15:00 KST임"
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps 검토",
        "detail": "목요일까지 가능하면 검토하자는 의견이 있었으나 담당자는 배정되지 않음"
      },
      {
        "topic": "최종 릴리스 승인 권한",
        "detail": "누가 최종 승인 권한을 갖는지 결정되지 않음"
      },
      {
        "topic": "릴리스 노트에 수요일 내부 stretch goal 언급 여부",
        "detail": "언급 여부가 결정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있음",
        "certainty": "confirmed"
      },
      {
        "risk": "README install steps가 오래된 경우 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있음",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      "누가 최종 릴리스 승인 권한을 갖는가?",
      "릴리스 노트에 수요일 내부 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke results를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed",
      "source_certainty": "explicit_no_exact_deadline"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "unassigned_non_decision",
      "source_certainty": "explicit_owner_not_assigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 smoke test 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "Doyun의 failure triage note가 action_items.md에 금요일 12:00 KST까지 작성되었는지 확인한다.",
      "smoke 결과 게시 후 Hara가 generated tarball path를 확인했는지 확인한다.",
      "README install steps 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 수요일 내부 stretch goal을 언급할지 결정한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너명",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "배정되지 않은 README 검토 담당자",
      "Hara의 정확한 마감일",
      "smoke test가 이미 통과했다는 사실",
      "금요일 15:00 KST 릴리스가 확정 실행된다는 사실"
    ]
  },
  "non_invention_rules": [
    {
      "rule": "회의록에는 fixture에 명시된 사실만 포함한다.",
      "applies_to": ["formal_minutes", "action_items", "followup_note"]
    },
    {
      "rule": "고객, 예산, 보안, 장애, 법무, 담당자, 마감일은 명시되지 않은 경우 생성하지 않는다.",
      "explicit_non_facts": [
        "customer name",
        "budget",
        "security incident",
        "production outage",
        "legal approval requirement"
      ]
    },
    {
      "rule": "수요일 릴리스는 확정 결정이 아니라 내부 stretch goal로만 기록한다."
    },
    {
      "rule": "README install steps 검토는 담당자가 없는 non-decision으로 기록한다."
    },
    {
      "rule": "Hara의 tarball path 확인은 smoke results 이후 수행으로만 기록하고 정확한 마감일은 null로 둔다."
    }
  ]
}
